UPDATE trans_list
SET trans_state =1
WHERE transshipment_id = #{trans.transshipmentId}

mapper.select:
SELECT * FROM product
WHERE product_num=#{transshipment.targetProductNum}
AND store_id = #{transshipment.targetStoreId}

SELECT count(*) FROM trans_list
AND target_store_id =#{trans.targetStoreId}
AND source_store_id =#{trans.sourceStoreId}
AND target_product_name like concat('%',#{trans.targetProductName},'%')
AND source_product_name like concat('%',#{trans.sourceProductName},'%')
AND create_name like concat('%',#{trans.createName},'%')

SELECT t1.*,t2.user_code
FROM trans_list t1,user_info t2
WHERE t2.user_id = t1.trans_by

    AND t1.target_store_id =#{trans.targetStoreId}


    AND t1.source_store_id =#{trans.sourceStoreId}


    AND t1.target_product_name like concat('%',#{trans.targetProductName},'%')


    AND t1.source_product_name like concat('%',#{trans.sourceProductName},'%')


    AND t1.create_name like concat('%',#{trans.createName},'%')

order by trans_date desc
limit #{page.limitIndex},#{page.pageSize}

SELECT t1.*,t2.store_id,t2.sale_price FROM trans_list t1,product t2
WHERE transshipment_id=#{trans.transshipmentId}
AND source_store_id = store_id
AND product_name= #{trans.targetProductName}

SELECT t1.target_store_id,t2.product_id,t1.trans_num,t2.store_id FROM trans_list t1,product t2
WHERE transshipment_id=#{trans.transshipmentId}
AND target_store_id = store_id
AND product_name= #{trans.targetProductName}
